#include "jayess_runtime.h"
#include <raylib.h>
#include <stdlib.h>

static unsigned char jayess_raylib_color_channel(jayess_object *object, const char *key, const char *context) {
    jayess_value *value = jayess_object_get(object, key);
    double number;
    if (value == NULL) {
        jayess_throw_type_error(context);
        return 0;
    }
    number = jayess_value_to_number(value);
    if (number < 0) number = 0;
    if (number > 255) number = 255;
    return (unsigned char) number;
}

static Color jayess_raylib_expect_color(jayess_value *value, const char *context) {
    jayess_object *object = jayess_expect_object(value, context);
    Color color = { 0, 0, 0, 255 };
    if (jayess_has_exception()) {
        return color;
    }
    color.r = jayess_raylib_color_channel(object, "r", context);
    if (jayess_has_exception()) return color;
    color.g = jayess_raylib_color_channel(object, "g", context);
    if (jayess_has_exception()) return color;
    color.b = jayess_raylib_color_channel(object, "b", context);
    if (jayess_has_exception()) return color;
    color.a = jayess_raylib_color_channel(object, "a", context);
    return color;
}

static jayess_value *jayess_raylib_value_from_vector2(Vector2 value) {
    jayess_object *object = jayess_object_new();
    jayess_object_set_value(object, "x", jayess_value_from_number((double) value.x));
    jayess_object_set_value(object, "y", jayess_value_from_number((double) value.y));
    return jayess_value_from_object(object);
}

static void jayess_raylib_image_finalize(void *handle) {
    Image *image = (Image *) handle;
    if (image != NULL) {
        if (IsImageValid(*image)) {
            UnloadImage(*image);
        }
        free(image);
    }
}

static void jayess_raylib_texture_finalize(void *handle) {
    Texture2D *texture = (Texture2D *) handle;
    if (texture != NULL) {
        if (IsTextureValid(*texture)) {
            UnloadTexture(*texture);
        }
        free(texture);
    }
}

static jayess_value *jayess_raylib_wrap_image(Image image, const char *message) {
    Image *stored = NULL;
    if (!IsImageValid(image)) {
        jayess_throw_named_error("RaylibError", message);
        return jayess_value_undefined();
    }
    stored = (Image *) malloc(sizeof(Image));
    if (stored == NULL) {
        UnloadImage(image);
        jayess_throw_error("failed to allocate raylib image handle");
        return jayess_value_undefined();
    }
    *stored = image;
    return jayess_value_from_managed_native_handle("RaylibImage", stored, jayess_raylib_image_finalize);
}

static jayess_value *jayess_raylib_wrap_texture(Texture2D texture, const char *message) {
    Texture2D *stored = NULL;
    if (!IsTextureValid(texture)) {
        jayess_throw_named_error("RaylibError", message);
        return jayess_value_undefined();
    }
    stored = (Texture2D *) malloc(sizeof(Texture2D));
    if (stored == NULL) {
        UnloadTexture(texture);
        jayess_throw_error("failed to allocate raylib texture handle");
        return jayess_value_undefined();
    }
    *stored = texture;
    return jayess_value_from_managed_native_handle("RaylibTexture", stored, jayess_raylib_texture_finalize);
}

