jayess_value *jayess_raylib_init_window(jayess_value *width_value, jayess_value *height_value, jayess_value *title_value) {
    int width = (int) jayess_value_to_number(width_value);
    int height = (int) jayess_value_to_number(height_value);
    const char *title = jayess_expect_string(title_value, "jayess_raylib_init_window");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    InitWindow(width, height, title);
    return jayess_value_from_bool(IsWindowReady());
}

